const promptData = $('Construir Prompt').first().json;
const resp = $input.first().json;

// Detectar erros de API (ex: MALFORMED_FUNCTION_CALL do Gemini)
const _choice = resp.choices?.[0];
const _finishReason = _choice?.finish_reason;
const _nativeReason = _choice?.native_finish_reason ?? '';
let content;
if (_finishReason === 'error' || _nativeReason.includes('MALFORMED')) {
  // Gemini gerou function call malformada - usar mensagem neutra
  // O modelo n�o conseguiu formular a resposta/tool call corretamente
  content = 'Desculpe, n�o consegui processar essa mensagem. Pode tentar novamente?';
} else {
  content = _choice?.message?.content ?? resp.error?.message ?? 'Desculpe, erro interno.';
}
// Detectar pedido expl�cito do usu�rio (regex) - o LLM �s vezes esquece o marcador
const _lastUserRaw = (() => {
  const lu = promptData.messages?.[promptData.messages.length - 1];
  if (typeof lu?.content === 'string') return lu.content;
  if (Array.isArray(lu?.content)) return lu.content.filter(p => p.type === 'text').map(p => p.text).join(' ');
  return '';
})().toLowerCase();
const _userPediuHumano = /(?:falar|conversar|atendimento|atendente|humano|pessoa\s+real|operador|gente\s+de\s+verdade)/.test(_lastUserRaw)
  && /(?:quero|preciso|posso|pode|me\s+(?:passa|conecta|transfere|liga)|chama|chamar|gostaria|atend(?:imento|ente)|humano)/.test(_lastUserRaw);
// Detectar frase de transfer�ncia na resposta do LLM
const _llmTransferiu = /(?:transferir|conectar|encaminhar|chamar|passar)\s+(?:voc[e�]|para)?\s*(?:um\s+)?atendente|atendente\s+(?:j[a�]\s+)?(?:vai|ir[a�])|vou\s+te\s+(?:transferir|conectar|passar)/i.test(content);
// Detectar e limpar marcador de escalada para humano
const escalarHumano = content.includes('[ESCALAR_HUMANO]') || (_userPediuHumano && _llmTransferiu) || _userPediuHumano;
content = content.replace(/\[ESCALAR_HUMANO\]/g, '').trim();

const historico = promptData.historico ?? [];

// ?? Detectar pedido expl�cito de �udio na �ltima mensagem do usu�rio ??????
const lastUserMsg = promptData.messages?.[promptData.messages.length - 1];
const userText = (
  typeof lastUserMsg?.content === 'string' ? lastUserMsg.content :
  Array.isArray(lastUserMsg?.content)
    ? lastUserMsg.content.filter(p => p.type === 'text').map(p => p.text).join(' ')
    : ''
).toLowerCase();

const pedidoAudio = /(?:manda?|envia?|responde?|fala)\s+(?:em\s+|por\s+|um\s+|uma?\s+)?[a�]udio|[a�]udio\s*(?:por favor|pfv?)?\s*$|prefiro\s+[a�]udio|pode\s+(?:falar|mandar\s+[a�]udio)|quero\s+(?:ouvir|[a�]udio)|em\s+[a�]udio|por\s+[a�]udio|fala\s+pra\s+mim/.test(userText);

const respondWithAudio = (promptData.respondWithAudio ?? false) || pedidoAudio || (promptData.tipo === 'audio');

// ?? Timestamp de agora (Brasil) ??????????????????????????????????????????
const agora = new Date();
const tsAgora = agora.toLocaleString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  hour: '2-digit', minute: '2-digit', day: '2-digit', month: '2-digit', year: 'numeric',
});

// ?? Converter conte�do multimodal em texto para o hist�rico ?????????????
const rawUserContent = promptData.messages[promptData.messages.length - 1]?.content;
let userContentForHistory;
if (Array.isArray(rawUserContent)) {
  const textParts = rawUserContent.filter(p => p.type === 'text').map(p => p.text).join(' ');
  userContentForHistory = textParts || '[imagem enviada]';
} else {
  userContentForHistory = typeof rawUserContent === 'string' ? rawUserContent : (promptData.conteudo || '');
}

// ?? Hist�rico com timestamps ?????????????????????????????????????????????
const novoHistorico = [
  ...historico,
  { role: 'user', content: userContentForHistory },
  { role: 'assistant', content: content.replace(/^\s*\[\d{2}\/\d{2}\/\d{4},?\s*\d{2}:\d{2}\]\s*/g, '').trim() },
].slice(-100);

const contexto = {
  instance: promptData.instance,
  telefone: promptData.telefone,
  remoteJid: promptData.remoteJid,
  historico: novoHistorico,
  businessId: promptData.businessId ?? '',
  conversation_id: promptData.conversation_id ?? '',
  account_id: promptData.account_id ?? '1',
};

// ?? Modo �UDIO: 1 item �nico ? TTS roda 1x, sem loop de chunks de texto ?
if (respondWithAudio) {
  // Strip timestamps copiados do hist�rico pelo LLM (ex: [23/05/2026, 20:24])
  const contentNoTimestamp = content.replace(/^\s*\[\d{2}\/\d{2}\/\d{4},?\s*\d{2}:\d{2}\]\s*/g, '').trim();
  const audioContent = contentNoTimestamp || content;
  return [{
    json: {
      chunk: audioContent,
      fullText: audioContent,
      isLast: true,
      respondWithAudio: true,
      escalarHumano,
      contexto,
      instance: promptData.instance,
      remoteJid: promptData.remoteJid,
      delay: 800,
      conversation_id: promptData.conversation_id ?? '',
      account_id: promptData.account_id ?? '1',
    }
  }];
}

// ?? Modo TEXTO: split em chunks normais ??????????????????????????????????
const chunks = content
  .replace(/^\s*\[\d{2}\/\d{2}\/\d{4},?\s*\d{2}:\d{2}\]\s*/, '')
  .split(/\n{2,}/)
  .map(s => s.trim())
  .filter(s => s.length > 0)
  .flatMap(s => {
    if (s.length <= 180) return [s];
    return s.match(/[^.!?]+[.!?]+/g)?.map(x => x.trim()).filter(Boolean) ?? [s];
  });

return chunks.map((texto, i) => ({
  json: {
    chunk: texto,
    fullText: content,
    isLast: i === chunks.length - 1,
    respondWithAudio: false,
    escalarHumano,
    contexto,
    instance: promptData.instance,
    remoteJid: promptData.remoteJid,
    delay: 800 + i * 600,
    conversation_id: promptData.conversation_id ?? '',
    account_id: promptData.account_id ?? '1',
  }
}));

const ttsResp = $input.first().json;
if (!ttsResp.base64) throw new Error('TTS falhou: ' + JSON.stringify(ttsResp));

const allChunks = $('Parsear Chunks').all();
const ctx = allChunks[allChunks.length - 1]?.json ?? {};

return [{
  json: {
    audioBase64: ttsResp.base64,
    instance: ctx.instance,
    remoteJid: ctx.remoteJid,
    evolutionAudioUrl: `https://evolution.vendly.chat/message/sendWhatsAppAudio/${ctx.instance}`,
    evolutionAudioBody: { number: ctx.remoteJid, audio: ttsResp.base64, encoding: true },
    contexto: ctx.contexto,
  }
}];

const item = $input.first().json;
const { instance, remoteJid, chunk, delay } = item;
const conversation_id = item.conversation_id ?? item.contexto?.conversation_id;
const account_id = item.account_id ?? item.contexto?.account_id ?? '1';
return [{
  json: {
    ...item,
    presenceUrl: `https://evolution.vendly.chat/chat/sendPresence/${instance}`,
    presenceBody: {
      number: remoteJid,
      presence: 'composing',
      delay: delay ?? 800,
    },
    evolutionUrl: `https://evolution.vendly.chat/message/sendText/${instance}`,
    evolutionBody: { number: remoteJid, text: chunk },
    chatwootUrl: `https://chatwoot.vendly.chat/api/v1/accounts/${account_id || '1'}/conversations/${conversation_id}/messages`,
    chatwootBody: { content: chunk, message_type: 'outgoing', private: false },
  }
}];

const item = $('Preparar Envio').first().json;
await new Promise(r => setTimeout(r, item.delay ?? 800));
return [{ json: item }];

const items = $input.all();
const last = items[items.length - 1]?.json ?? {};
return [{ json: { contexto: last.contexto } }];

