return [{
  json: {
    key: businessId + ':' + phone,
    businessId,
    instance,
    phone,
    name: msg.pushName || phone,
    last_seen: new Date().toISOString(),
  }
}];

const items = $input.all();
const last = items[items.length - 1]?.json ?? {};
const ctx = last.contexto ?? {};
return [{
  json: {
    businessId: ctx.businessId || ctx.instance,
    instance: ctx.instance,
    phone: ctx.telefone,
    started_at: new Date().toISOString(),
    messages: (ctx.historico ?? []).slice(-20),
    model_used: ctx.model ?? 'google/gemini-2.5-flash-preview',
  }
}];

// L� hist�rico e verifica se precisa de compress�o
const sessao = $input.first().json;
let historico = [];
try {
  const raw = sessao.value ?? null;
  if (typeof raw === 'string') historico = JSON.parse(raw);
  else if (Array.isArray(raw)) historico = raw;
} catch {}

// Estima tokens: ~3.5 chars/token (conservador para pt-BR com timestamps)
const totalChars = historico.reduce((acc, m) => {
  const c = typeof m.content === 'string' ? m.content : JSON.stringify(m.content ?? '');
  return acc + c.length;
}, 0);
const estimatedTokens = Math.ceil(totalChars / 3.5);

// 500k = 50% de 1M (deixa 50% para system prompt, msgs atuais e resposta)
const THRESHOLD = 500_000;
const COMPRESS_RATIO = 0.30; // comprimir 30% mais antigas

const needsSummarize = estimatedTokens > THRESHOLD && historico.length >= 20;
const compressCount = needsSummarize ? Math.floor(historico.length * COMPRESS_RATIO) : 0;

return [{ json: { historico, needsSummarize, compressCount, estimatedTokens } }];

// Prepara payload para resumir as mensagens mais antigas
const { historico, compressCount } = $input.first().json;
const oldest = historico.slice(0, compressCount);
const remaining = historico.slice(compressCount);

// Formatar conversa para summariza��o
const conversation = oldest.map(m => {
  const role = m.role === 'user' ? 'Cliente' : m.role === 'assistant' ? 'Assistente' : 'Sistema';
  const content = typeof m.content === 'string' ? m.content : '[conte�do n�o-textual]';
  return role + ': ' + content;
}).join('\n');

const openrouterBody = {
  model: 'google/gemini-2.5-flash-preview',
  messages: [
    {
      role: 'system',
      content: 'Resuma esta conversa em portugu�s. Preserve: nome do cliente (se mencionado), prefer�ncias expressas, problemas relatados, decis�es tomadas, datas/hor�rios importantes, informa��es de pedidos ou produtos, e qualquer fato relevante para o atendimento futuro. Seja conciso (m�ximo 400 palavras).'
    },
    { role: 'user', content: conversation }
  ],
  max_tokens: 600,
};

return [{ json: { openrouterBody, remaining, compressCount } }];

// Monta hist�rico com resumo + mensagens recentes
const resp = $input.first().json;
const { remaining, compressCount } = $('Preparar Resumo').first().json;

const summary = resp.choices?.[0]?.message?.content ?? '';

let historico;
if (summary) {
  // Resumo como par user/assistant - sem messages do tipo system no hist�rico
  historico = [
    { role: 'user', content: '[Resumo das ' + compressCount + ' mensagens anteriores]: ' + summary },
    { role: 'assistant', content: 'Entendido.' },
    ...remaining,
  ];
} else {
  // Fallback: descarta as mais antigas sem resumo (evita context overflow)
  historico = remaining;
}

return [{ json: { historico } }];

// Mescla hist�rico do Redis (sess�o LLM) com hist�rico do Chatwoot (fonte da verdade)
// Estrat�gia: usar o que tiver MAIS mensagens - geralmente Chatwoot tem todo o hist�rico
// quando o Redis est� vazio (conversa nova / cache perdido)

const inputItem = $input.first().json;
const redisHist = Array.isArray(inputItem.historico) ? inputItem.historico : [];

let cwHist = [];
try {
  cwHist = $('Preparar Hist�rico Chatwoot').first().json.historico ?? [];
} catch {}

// Se Chatwoot tem mais hist�rico que Redis, usa Chatwoot (fallback robusto)
// Sen�o usa Redis (que pode ter resumo comprimido)
const historico = cwHist.length > redisHist.length ? cwHist : redisHist;

return [{ json: { historico } }];

const resp = $input.first().json;
const tc = resp.choices?.[0]?.message?.tool_calls?.[0];
if (!tc) return [];
let args = {};
try { args = JSON.parse(tc.function?.arguments ?? '{}'); } catch {}
const name = tc.function?.name || '';
const isMcp = name.startsWith('delivery_');
return [{
  json: {
    toolCallId: tc.id,
    toolName: name,
    isMcp,
    query: args.query ?? '',
    args,
    assistantMessage: resp.choices[0].message,
  }
}];

