// Processar escalada para atendimento humano
const chunks = $('Parsear Chunks').all();
const hasEscalada = chunks.some(i => i.json.escalarHumano === true);
if (!hasEscalada) return [];

const ctx = chunks[0]?.json?.contexto ?? {};
const { instance, telefone, conversation_id, account_id } = ctx;
if (!instance || !telefone) return [];

// Contexto extra para sinais Chatwoot e notifica��es WhatsApp
const accId = String(account_id || '1');
const convId = String(conversation_id);
const promptData = $('Construir Prompt').first().json;
const customerName = promptData?.customerName || ctx.customerName || 'Cliente';
const lastUserMsg = promptData?.messages?.[promptData.messages.length - 1];
const lastUserText = (
  typeof lastUserMsg?.content === 'string' ? lastUserMsg.content :
  Array.isArray(lastUserMsg?.content)
    ? lastUserMsg.content.filter(p => p.type === 'text').map(p => p.text).join(' ')
    : ''
).replace(/^\*\*[^*]+\*\*\s*\n+/, '').trim();
const botResponse = chunks.map(c => c.json.chunk).filter(Boolean).join('\n');

const businessDoc = $('MongoDB GET Business').first().json;
const notifyList = Array.isArray(businessDoc?.escalationNotifyList) ? businessDoc.escalationNotifyList : [];

return [{
  json: {
    takeover_key: 'human_takeover:' + instance + ':' + telefone,
    takeover_value: 'escalado',
    conversation_id: convId,
    account_id: accId,
    instance,
    chatwoot_base: 'https://chatwoot.vendly.chat/api/v1/accounts/' + accId + '/conversations/' + convId,
    chatwoot_app_url: 'https://chatwoot.vendly.chat/app/accounts/' + accId + '/conversations/' + convId,
    customer_name: customerName,
    last_user_text: lastUserText,
    bot_response: botResponse,
    notify_list: notifyList,
  },
}];

const e = $input.first().json;
const list = Array.isArray(e.notify_list) ? e.notify_list : [];
if (!list.length) return [];
const text =
  '?? *Pedido de atendimento humano*\n\n' +
  'Cliente: ' + (e.customer_name || 'Desconhecido') + '\n' +
  '�ltima mensagem: "' + String(e.last_user_text || '').slice(0, 200) + '"\n' +
  'Resposta do bot: "' + String(e.bot_response || '').slice(0, 200) + '"\n\n' +
  '?? Abrir conversa:\n' + e.chatwoot_app_url;
return list.map(num => {
  const digits = String(num).replace(/\D/g, '');
  if (!digits) return null;
  const jid = digits + '@s.whatsapp.net';
  return { json: { instance: e.instance, number: jid, text } };
}).filter(Boolean);

// Resolve qual persona aplicar a esta mensagem com base em persona_routes:{instance}.
// IMPORTANTE: Redis GET typeVersion 1 substitui o item por {persona_raw: ...} - restaura
// o item original via $('Desembalar Payload').first().json (mesmo padr�o de "Aplicar Filtro Contatos").
// Sem rotas configuradas = nada acontece (compatibilidade total com fluxo antigo).
const item = $('Desembalar Payload').first().json;
const raw = $input.first().json?.persona_raw ?? null;

if (!raw) return [{ json: item }];

let cfg = null;
try { cfg = JSON.parse(String(raw)); } catch { cfg = null; }
if (!cfg || !Array.isArray(cfg.routes)) return [{ json: item }];

const remoteJid = String(item.remoteJid || '');
const telefone = String(item.telefone || '');
const route = cfg.routes.find(r => r.jid === remoteJid)
  || cfg.routes.find(r => r.jid === telefone)
  || null;

if (!route) return [{ json: item }];

const personas = cfg.personas || {};
const persona = personas[route.personaKey] || null;

return [{
  json: {
    ...item,
    personaKey: route.personaKey,
    personaLabel: persona?.label ?? route.personaKey,
    systemPromptOverride: persona?.systemPrompt ?? '',
    toolsAllowed: Array.isArray(persona?.tools) ? persona.tools : [],
    restaurantId: route.restaurantId ?? null,
  },
}];

// Parse resposta MCP (text/event-stream → SSE: "event: message\ndata: {...}")
const raw = $input.first().json;
const extr = $('Extrair Query Ferramenta').first().json;
const promptData = $('Construir Prompt').first().json;

let textResult = '';
try {
  const body = raw.data ?? raw.body ?? (typeof raw === 'string' ? raw : JSON.stringify(raw));
  const dataLine = String(body).split('\n').find(l => l.startsWith('data: '));
  const jsonStr = dataLine ? dataLine.slice(6) : String(body);
  const parsed = JSON.parse(jsonStr);
  if (parsed.error) {
    textResult = 'Erro MCP: ' + (parsed.error.message || JSON.stringify(parsed.error));
  } else {
    const content = parsed.result?.content?.[0]?.text;
    textResult = content || JSON.stringify(parsed.result);
  }
} catch (e) {
  textResult = 'Erro parseando resposta MCP: ' + e.message + ' | raw=' + String(raw).slice(0, 200);
}

let baseBody = {};
try { baseBody = JSON.parse(promptData.openRouterBody); } catch(_) { baseBody = { model: promptData.model, messages: promptData.messages, temperature: 0.8 }; }

const newMessages = [
  ...(baseBody.messages || promptData.messages || []),
  extr.assistantMessage,
  { role: 'tool', tool_call_id: extr.toolCallId, content: textResult },
];

// SEMPRE 'auto' na 2a chamada — evita loop de tool_calls e permite resposta em texto final
const outBody = { ...baseBody, messages: newMessages, tool_choice: 'auto' };

return [{ json: { ...outBody, openRouterBody: JSON.stringify(outBody) } }];
